    58→]);
    59→
    60→function looksLikeIngredient(line: string): boolean {
    61→  const lowerLine = line.toLowerCase();
    62→  return MEASUREMENT_PATTERNS.some((pattern) => lowerLine.includes(pattern));
    63→}
    64→
    65→function startsWithNumber(line: string): boolean {
    66→  return /^\s*\d/.test(line);
    67→}
    68→
    69→function isAllCaps(line: string): boolean {
    70→  const letters = line.replace(/[^a-zA-Z]/g, "");
    71→  return letters.length > 0 && letters === letters.toUpperCase();
    72→}
    73→
    74→function looksLikeMetadata(text: string): boolean {
    75→  return METADATA_PATTERNS.some((pattern) => pattern.test(text.trim()));
    76→}
    77→
    78→function isLikelyGarbled(text: string): boolean {
    79→  const letters = text.replace(/[^a-zA-Z]/g, "");
    80→  if (letters.length < 2) return true;
    81→
    82→  // Check vowel ratio — English/Polish text typically has 30–50% vowels
    83→  const vowels = letters.replace(/[^aeiouAEIOUyYąęóĄĘÓ]/g, "").length;
    84→  const vowelRatio = vowels / letters.length;
    85→  if (vowelRatio < 0.15 || vowelRatio > 0.85) return true;
    86→
    87→  // Single orphaned word ≤3 letters that isn't a common word
    88→  const words = text.trim().split(/\s+/);
    89→  const COMMON_SHORT = new Set([
    90→    "the", "and", "for", "but", "not", "you", "all", "can", "had", "her",
    91→    "was", "one", "our", "out", "are", "has", "his", "how", "its", "may",
    92→    "new", "now", "old", "see", "way", "who", "did", "get", "let", "say",
    93→    "she", "too", "use",
    94→  ]);
    95→  if (words.length === 1 && letters.length <= 3 && !COMMON_SHORT.has(text.trim().toLowerCase())) {
    96→    return true;
    97→  }
    98→
    99→  // Line starts with lowercase and is a short sentence fragment — OCR corruption indicator
   100→  if (text.length < 25 && /^[a-z]/.test(text.trim()) && !text.trim().endsWith(".")) {
   101→    return true;
   102→  }
   103→
   104→  return false;
   105→}
   106→
   107→function passesHardFilters(text: string): boolean {
   108→  if (text.length < 3 || text.length > 80) return false;
   109→  if (looksLikeIngredient(text)) return false;
   110→  if (startsWithNumber(text)) return false;
   111→  if (looksLikeMetadata(text)) return false;
   112→  if (isLikelyGarbled(text)) return false;
   113→  // Single-word non-title fragments
   114→  const words = text.trim().split(/\s+/);
   115→  if (words.length === 1 && NON_TITLE_WORDS.has(text.trim().toLowerCase())) return false;
   116→  return true;
   117→}
   118→
   119→/**
   120→ * Detect initial burst of short garbled lines.
   121→ * Returns the index of the first non-garbled or long line.
   122→ */
   123→function findBurstEnd(lines: Array<{ text: string }>): number {
   124→  let i = 0;
   125→  while (i < lines.length && lines[i].text.length < 20 && isLikelyGarbled(lines[i].text)) {
   126→    i++;
   127→  }
   128→  return i;
   129→}
   130→
   131→function wordCount(text: string): number {
   132→  return text.split(/\s+/).filter((w) => w.length > 0).length;
   133→}
   134→
   135→/**
   136→ * Build candidate strings from lines: single lines plus multi-line joins (2-3 consecutive).
   137→ * Skips initial burst of short garbled lines. Scans all remaining lines. Caps at 25.
   138→ */
   139→function buildCandidates(
   140→  lines: Array<string>
   141→): Array<{ text: string; position: number }> {
   142→  const nonEmptyLines: Array<{ text: string; index: number }> = [];
   143→
   144→  for (let i = 0; i < lines.length; i++) {
   145→    const trimmed = lines[i].trim();
   146→    if (trimmed.length > 0) {
   147→      nonEmptyLines.push({ text: trimmed, index: i });
   148→    }
   149→  }
   150→
   151→  const burstEnd = findBurstEnd(nonEmptyLines);
   152→  const candidates: Array<{ text: string; position: number }> = [];
   153→  const seen = new Set<string>();
   154→
   155→  for (let i = burstEnd; i < nonEmptyLines.length; i++) {
   156→    const line = nonEmptyLines[i];
   157→
   158→    // Single line
   159→    if (passesHardFilters(line.text)) {
   160→      const norm = line.text.toLowerCase();
   161→      if (!seen.has(norm)) {
   162→        seen.add(norm);
   163→        candidates.push({ text: line.text, position: line.index });
   164→      }
   165→    }
   166→
   167→    // 2-line join
   168→    if (i + 1 < nonEmptyLines.length) {
   169→      const joined2 = `${line.text} ${nonEmptyLines[i + 1].text}`;
   170→      if (passesHardFilters(joined2)) {
   171→        const norm = joined2.toLowerCase();
   172→        if (!seen.has(norm)) {
   173→          seen.add(norm);
   174→          candidates.push({ text: joined2, position: line.index });
   175→        }
   176→      }
   177→    }
   178→
   179→    // 3-line join
   180→    if (i + 2 < nonEmptyLines.length) {
   181→      const joined3 = `${line.text} ${nonEmptyLines[i + 1].text} ${nonEmptyLines[i + 2].text}`;
   182→      if (passesHardFilters(joined3)) {
   183→        const norm = joined3.toLowerCase();
   184→        if (!seen.has(norm)) {
   185→          seen.add(norm);
   186→          candidates.push({ text: joined3, position: line.index });
   187→        }
   188→      }
   189→    }
   190→  }
   191→
   192→  // Pre-filter to 25 before embedding calls: prefer ALL_CAPS and short candidates.
   193→  // Position-based scoring handles final ranking.
   194→  if (candidates.length > 25) {
   195→    const prioritized = candidates.slice().sort((a, b) => {
   196→      const aAllCaps = isAllCaps(a.text) ? 0 : 1;
   197→      const bAllCaps = isAllCaps(b.text) ? 0 : 1;
   198→      if (aAllCaps !== bAllCaps) return aAllCaps - bAllCaps;
   199→      const aShort = wordCount(a.text) <= 5 ? 0 : 1;
   200→      const bShort = wordCount(b.text) <= 5 ? 0 : 1;
   201→      return aShort - bShort;
   202→    });
   203→    return prioritized.slice(0, 25);
   204→  }
   205→
   206→  return candidates;
   207→}
   208→
   209→// Module-level cache for reference embeddings
   210→let cachedTitleRefEmbedding: Array<number> | null = null;
   211→let cachedHeaderRefEmbedding: Array<number> | null = null;
   212→let cachedNoiseRefEmbedding: Array<number> | null = null;
   213→
   214→export function _resetEmbeddingCacheForTests(): void {
   215→  cachedTitleRefEmbedding = null;
   216→  cachedHeaderRefEmbedding = null;
   217→  cachedNoiseRefEmbedding = null;
   218→}
   219→
   220→export async function extractTitleWithEmbeddings(
   221→  text: string,
   222→  embed: EmbedFn
   223→): Promise<string | undefined> {
   224→  if (!text || text.trim().length === 0) {
   225→    return undefined;
   226→  }
   227→
   228→  const lines = text.split("\n");
